import jsPDF from 'jspdf';
import type { Persona } from '../types';

export const generateDocumentoCoursera = async (persona: Persona) => {
    const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
    });

    const pageWidth = doc.internal.pageSize.getWidth();
    const marginLeft = 25;
    const marginRight = 25;

    // --- LOGOS (Imagen 1 e Imagen 2 integradas) ---
    const logoUabc =  ''
    const logoCoursera = ''
    
    try {
        doc.addImage(logoUabc, 'PNG', 15, 10, 80, 25);
        doc.addImage(logoCoursera, 'PNG', pageWidth - 65, 10, 50, 25);
    } catch (e) { console.error("Error al cargar logos"); }

    let y = 50;

    // --- TÍTULOS ---
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text('CONVOCATORIA SEMESTRAL 2026-1', pageWidth / 2, y, { align: 'center' });
    y += 5;
    doc.text('CERTIFICACIONES PROFESIONALES UABC + COURSERA', pageWidth / 2, y, { align: 'center' });
    
    y += 15;
    doc.setFontSize(12);
    doc.text('CARTA COMPROMISO', pageWidth / 2, y, { align: 'center' });
    const tw = doc.getTextWidth('CARTA COMPROMISO');
    doc.setLineWidth(0.5);
    doc.line((pageWidth / 2) - (tw / 2), y + 1, (pageWidth / 2) + (tw / 2), y + 1);

    // --- FECHA (Alineada a la derecha) ---
    y += 15;
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(11);
    const hoy = new Date();
    const fecha = `Mexicali, B.C., a ${hoy.getDate()} de ${obtenerNombreMes(hoy.getMonth())} del ${hoy.getFullYear()}`;
    doc.text(fecha, pageWidth - marginRight, y, { align: 'right' });

    // --- CUERPO DEL TEXTO (Negrita + Cursiva + Subrayado en entradas) ---
    y += 20;
    const lineHeight = 7;
    let currentX = marginLeft;

    const write = (text: string, style: 'normal' | 'variable' = 'normal') => {
        // Estilo 'variable' aplica: Negrita, Cursiva y Subrayado
        if (style === 'variable') {
            doc.setFont('helvetica', 'bolditalic');
        } else {
            doc.setFont('helvetica', 'normal');
        }

        const words = text.split(' ');
        words.forEach((word, index) => {
            const wordWithSpace = word + (index === words.length - 1 ? '' : ' ');
            const wordWidth = doc.getTextWidth(wordWithSpace);

            if (currentX + wordWidth > pageWidth - marginRight) {
                currentX = marginLeft;
                y += lineHeight;
            }

            doc.text(wordWithSpace, currentX, y);
            
            if (style === 'variable') {
                const onlyWordWidth = doc.getTextWidth(word);
                doc.setLineWidth(0.3);
                // Línea de subrayado
                doc.line(currentX, y + 0.8, currentX + onlyWordWidth, y + 0.8);
            }
            
            currentX += wordWidth;
        });
    };

    write("Por este conducto manifiesto expresamente al Centro de Investigación para el Aprendizaje Digital, organizador de la ");
    write("Convocatoria Semestral de Certificaciones Profesionales UABC + COURSERA 2026-1", 'variable');
    write(" mi compromiso de culminar de manera exitosa y dentro del tiempo estipulado la certificación profesional denominada ");
    write(persona.cursoCoursera, 'variable');
    write(", ofertada por ");
    write(persona.ofertadaPor, 'variable');
    write(" y la cual está compuesta de ");
    write(persona.numeroCursos.toString().padStart(2, '0'), 'variable');
    write(" cursos y tiene una duración de ");
    write(persona.duracionHoras.toString(), 'variable');
    write(" horas.");

    // --- FIRMAS ---
    y += 45;
    doc.setFont('helvetica', 'bold');
    doc.text('A T E N T A M E N T E .', pageWidth / 2, y, { align: 'center' });
    
    y += 30;
    doc.setLineWidth(0.4);
    doc.line(pageWidth / 2 - 40, y, pageWidth / 2 + 40, y);
    y += 5;
    doc.text(persona.nombreCompleto.toUpperCase(), pageWidth / 2, y, { align: 'center' });
    y += 5;
    doc.text(persona.matriculaUABC, pageWidth / 2, y, { align: 'center' });

    y += 30;
    doc.line(pageWidth / 2 - 40, y, pageWidth / 2 + 40, y);
    y += 5;
    doc.text('DR. JESUS EDUARDO SOTO VEGA', pageWidth / 2, y, { align: 'center' });
    y += 5;
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text('RPE de la Licenciatura en Sistemas Computacionales', pageWidth / 2, y, { align: 'center' });

    doc.save(`Carta_Compromiso_${persona.matriculaUABC}.pdf`);
};

export const generateCertificadoCoursera = (persona: Persona) => {
    const doc = new jsPDF({
        orientation: 'portrait',
        unit: 'mm',
        format: 'a4'
    });

    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 18;
    const hoy = new Date();
    const fecha = `${hoy.getDate()} de ${obtenerNombreMes(hoy.getMonth())} de ${hoy.getFullYear()}`;

    const logoUabc =  ''
    const logoCoursera = ''

    doc.setDrawColor(25, 62, 114);
    doc.setLineWidth(1.2);
    doc.rect(margin, margin, pageWidth - margin * 2, pageHeight - margin * 2);

    doc.setDrawColor(188, 154, 78);
    doc.setLineWidth(0.4);
    doc.rect(margin + 3, margin + 3, pageWidth - (margin + 3) * 2, pageHeight - (margin + 3) * 2);

    try {
        if (logoUabc) {
            doc.addImage(logoUabc, 'PNG', margin + 6, margin + 6, 55, 18);
        }
        if (logoCoursera) {
            doc.addImage(logoCoursera, 'PNG', pageWidth - margin - 36, margin + 6, 30, 18);
        }
    } catch (e) {
        console.error('Error al cargar logos del certificado');
    }

    let y = 56;

    doc.setFont('times', 'bold');
    doc.setFontSize(26);
    doc.text('CERTIFICADO DE FINALIZACION', pageWidth / 2, y, { align: 'center' });

    y += 10;
    doc.setFont('times', 'bolditalic');
    doc.setFontSize(15);
    doc.text('UABC + Coursera', pageWidth / 2, y, { align: 'center' });

    y += 20;
    doc.setFont('times', 'normal');
    doc.setFontSize(13);
    doc.text('Se otorga el presente certificado a:', pageWidth / 2, y, { align: 'center' });

    y += 15;
    doc.setFont('times', 'bold');
    doc.setFontSize(22);
    doc.text(persona.nombreCompleto.toUpperCase(), pageWidth / 2, y, { align: 'center' });

    y += 7;
    doc.setLineWidth(0.5);
    doc.line(pageWidth / 2 - 70, y, pageWidth / 2 + 70, y);

    y += 16;
    doc.setFont('times', 'normal');
    doc.setFontSize(13);
    doc.text('por haber completado satisfactoriamente la certificacion profesional:', pageWidth / 2, y, { align: 'center' });

    y += 13;
    doc.setFont('times', 'bolditalic');
    doc.setFontSize(18);
    doc.text(persona.cursoCoursera, pageWidth / 2, y, {
        align: 'center',
        maxWidth: pageWidth - 50
    });

    y += 18;
    doc.setFont('times', 'normal');
    doc.setFontSize(12);
    doc.text(`Plataforma: ${persona.ofertadaPor}`, pageWidth / 2, y, { align: 'center' });

    y += 8;
    doc.text(`Numero de cursos: ${persona.numeroCursos} | Duracion: ${persona.duracionHoras} horas`, pageWidth / 2, y, { align: 'center' });

    y += 13;
    doc.setFont('times', 'normal');
    doc.setFontSize(11);
    doc.text(`Matricula UABC: ${persona.matriculaUABC} | CURP: ${persona.curp}`, pageWidth / 2, y, {
        align: 'center',
        maxWidth: pageWidth - 40
    });

    y += 7;
    doc.text(`Fecha de nacimiento: ${persona.fechaNacimiento} | Lugar de nacimiento: ${persona.lugarNacimiento}`, pageWidth / 2, y, {
        align: 'center',
        maxWidth: pageWidth - 40
    });

    y += 23;
    doc.setFontSize(11);
    doc.text(`Mexicali, B.C., ${fecha}`, pageWidth / 2, y, { align: 'center' });

    y += 30;
    doc.setLineWidth(0.4);
    doc.line(pageWidth / 2 - 60, y, pageWidth / 2 + 60, y);

    y += 6;
    doc.setFont('times', 'bold');
    doc.setFontSize(11);
    doc.text('Centro de Investigacion para el Aprendizaje Digital', pageWidth / 2, y, { align: 'center' });

    y += 5;
    doc.setFont('times', 'normal');
    doc.setFontSize(10);
    doc.text('Universidad Autonoma de Baja California', pageWidth / 2, y, { align: 'center' });

    doc.save(`Certificado_Coursera_${persona.matriculaUABC}.pdf`);
};

function obtenerNombreMes(m: number): string {
    return ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'][m];
}